<?php
namespace App\Services\Finance;use App\Contracts\Payments\PaymentProviderInterface;use App\Services\Finance\Providers\VippsMobilePayPaymentProvider;use App\Settings\OperationsSettings;
class PaymentProviderManager{public function __construct(private DisabledPaymentProvider $disabled,private VippsMobilePayPaymentProvider $vipps,private PaymentProviderSecretService $secrets){}public function provider():PaymentProviderInterface{return $this->settings()->payment_provider_key==='vipps_mobilepay_sandbox'?$this->vipps:$this->disabled;}public function status():array{$s=$this->settings();$r=$this->secrets->readiness('vipps_mobilepay',$s->vipps_mobilepay_environment);$checks=['provider_selected'=>$s->payment_provider_key==='vipps_mobilepay_sandbox','sandbox_environment'=>$s->vipps_mobilepay_environment==='sandbox','merchant_serial_number'=>preg_match('/^\d{4,10}$/',(string)$s->vipps_mobilepay_merchant_serial_number)===1,'return_https'=>$this->https($s->vipps_mobilepay_return_url),'callback_https'=>$this->https($s->vipps_mobilepay_callback_url),'secrets_present'=>$r['ready'],'webhook_verifier'=>'fail_closed','outbound_http_allowed'=>$s->vipps_mobilepay_outbound_http_allowed,'production'=>'deferred'];$missing=collect($checks)->filter(fn($v)=>$v===false)->keys()->all();return ['key'=>$s->payment_provider_key,'environment'=>$s->vipps_mobilepay_environment,'configured'=>empty($missing)&&$checks['webhook_verifier']!=='fail_closed','checks'=>$checks,'missing'=>$missing,'outbound_http_enabled'=>false,'reason'=>empty($missing)?'Webhook algorithm confirmation and outbound approval are still required.':'Missing or invalid: '.implode(', ',$missing)];}private function settings():OperationsSettings{return app(OperationsSettings::class);}private function https(?string $url):bool{return filled($url)&&filter_var($url,FILTER_VALIDATE_URL)&&str_starts_with($url,'https://');}}